func GetGOBIN() string {

	gobin := strings.TrimSpace(Get("GOBIN", ""))
	if gobin == "" {
		var err error

		gobin, err = GetRuntimeEnv("GOBIN")
		if err != nil {

			return filepath.Join(build.Default.GOPATH, "bin")
		}
		if gobin == "" {
			return filepath.Join(build.Default.GOPATH, "bin")
		}
		return gobin
	}
	return gobin
}
